module sr_latch (
    input wire clk,
    input wire S,
    input wire R,
    output reg obf_Q
);
    always @(posedge clk) begin
        if (S && !R)
            obf_Q <= 1;  // Set
        else if (!S && R)
            obf_Q <= 0;  // Reset
        // If both S and R are low, obf_Q retains its state
    end
endmodule
